/**
 * Get initial user information
 * 
 * by Manuel Monroy
 */

let user = {};
if (this._user != undefined) {
    user.ID = this._user.id;
    user.NAME = this._user.fullname;
    user.EMAIL = this._user.email;
}

return user;

/**
 * Check if an uploaded document exists
 * 
 * by Manuel Monroy
 */

let idPdf = this.IN_UPLOAD_PDF;
let idExcel = this.IN_UPLOAD_EXCEL;

if (idPdf === null && idExcel === null ) {
    return true;
} 
return false

/**
 * Check pdfs and excels
 * 
 * by Favio Mollinedo
 */

let idPdf = this.IN_UPLOAD_PDF;
let idExcel = this.IN_UPLOAD_EXCEL;

const onlyPdf = idPdf !== null && idExcel === null;
const onlyExcel = idPdf === null && idExcel !== null;
const bothFiles = idPdf !== null && idExcel !== null;

return !onlyPdf;

/**
 * Set Upload Icons
 * by Favio Mollinedo
 * Modified by Ana Castillo
 */
$(document).ready(function() {
    $("label:contains('PDF Invoice')").each(function() {
        $(this).css("font-weight","Bold");
        if ($(this).find("i.pdf-icon").length === 0) {
            $(this).append('<i class="fas fa-file-pdf pdf-icon" style="margin-left: 5px;"></i>');
        }
    });
    $("label:contains('Excel Invoice')").each(function() {
        $(this).css("font-weight","Bold");
        if ($(this).find("i.excel-icon").length === 0) {
            $(this).append('<i class="fas fa-file-excel excel-icon" style="margin-left: 5px;"></i>');
        }
    });
    $("label:contains('Additional Documents')").each(function() {
        $(this).css("font-weight","Bold");
    });
    $('label[aria-label="PDF Invoice"]').contents().filter(function() {
        return this.nodeType === 3;
    }).each(function() {
        this.textContent = this.textContent.replace("select file", "select pdf file");
    });
    $('label[aria-label="Excel Invoice"]').contents().filter(function() {
        return this.nodeType === 3;
    }).each(function() {
        this.textContent = this.textContent.replace("select file", "select excel file");
    });
});
//return true;

let result = [];
if(this.IN_TEMPLATE_ID != null && this.IN_TEMPLATE_ID != undefined && this.IN_TEMPLATE_ID != ""){
    let idToFind = this.IN_TEMPLATE_ID;
    result = this.EXCEL_TEMPLATE_DATA.find(item => item.ID == idToFind);
    return result["STATIC_INFORMATION"] == "true" ? true : false;
}
return false;

let result = [];
if(this.IN_TEMPLATE_ID != null && this.IN_TEMPLATE_ID != undefined && this.IN_TEMPLATE_ID != ""){
    let idToFind = this.IN_TEMPLATE_ID;
    result = this.EXCEL_TEMPLATE_DATA.find(item => item.ID == idToFind);
    return result;
}
return result;

/**
 * 
 * By Favio Molliendo.
 */
if(this._request.errors != null && !this.EXISTS_ERROR_EXCEL){
    return "";
}
return this.EXCEL_ERROR_TAB;

